pub fn init(&mut self)
        requires
            old(self).wf(),
        ensures
            self.wf(),
            self@ == Set::<usize>::empty(),
    {
            self.len = 0;
            self.set = Ghost(Set::<usize>::empty());
        for i in 0..N
            invariant
                0<=i<=N,
                self.data.wf(),
                self.len == 0,
                self.set@ == Set::<usize>::empty(),
                forall|j:int|
                    0<=j<i ==> self.data@[j] == false,
        {
            self.data.set(i,false);
        }
    }

pub fn new() -> (ret:Self)
        ensures
            ret.wf(),
            ret@ == Set::<usize>::empty(),
    {
        let mut ret = Self{
            data: Array::new(),
            len: 0,
            set:Ghost(Set::<usize>::empty()),
        };
        for i in 0..N
            invariant
                0<=i<=N,
                ret.data.wf(),
                ret.len == 0,
                ret.set@ == Set::<usize>::empty(),
                forall|j:int|
                    0<=j<i ==> ret.data@[j] == false,
        {
            ret.data.set(i,false);
        }
        ret
    }

#[verifier::spinoff_prover]
    pub fn check_address_space_va_range_free(
        &self,
        target_proc_ptr: ProcPtr,
        va_range: &VaRange4K,
    ) -> (ret: bool)
        requires
            self.wf(),
            self.proc_dom().contains(target_proc_ptr),
            va_range.wf(),
        ensures
            ret == self.address_space_range_free(target_proc_ptr, va_range),
    {
        let target_pcid = self.proc_man.get_proc(target_proc_ptr).pcid;
        for i in 0..va_range.len
            invariant
                self.mem_man.pcid_active(target_pcid),
                target_pcid == self.get_proc(target_proc_ptr).pcid,
                0 <= i <= va_range.len,
                self.wf(),
                self.proc_dom().contains(target_proc_ptr),
                va_range.wf(),
                forall|j: int|
                    #![auto]
                    0 <= j < i ==> self.get_address_space(target_proc_ptr).dom().contains(
                        va_range@[j],
                    ) == false,
        {
            if self.mem_man.resolve_pagetable_mapping(target_pcid, va_range.index(i)).is_some() {
                return false;
            }
        }
        return true;
    }

pub fn alloc_and_map(
        &mut self,
        target_proc_ptr: ProcPtr,
        target_va: VAddr,
        tagret_l1_p: PageMapPtr,
    ) -> (ret: MapEntry)
        requires
            old(self).wf(),
            old(self).proc_dom().contains(target_proc_ptr),
            old(self).get_container_quota(
                old(self).get_proc(target_proc_ptr).owning_container,
            ).mem_4k >= 1,
            old(self).get_num_of_free_pages() >= 1,
            va_4k_valid(target_va),
            old(self).get_address_space(target_proc_ptr).dom().contains(target_va) == false,
            old(self).mem_man.get_pagetable_by_pcid(
                old(self).get_proc(target_proc_ptr).pcid,
            ).unwrap().spec_resolve_mapping_l2(
                spec_va2index(target_va).0,
                spec_va2index(target_va).1,
                spec_va2index(target_va).2,
            ).is_Some(),
            old(self).mem_man.get_pagetable_by_pcid(
                old(self).get_proc(target_proc_ptr).pcid,
            ).unwrap().spec_resolve_mapping_l2(
                spec_va2index(target_va).0,
                spec_va2index(target_va).1,
                spec_va2index(target_va).2,
            ).unwrap().addr == tagret_l1_p,
        ensures
            self.wf(),
            self.proc_dom() == old(self).proc_dom(),
            self.thread_dom() == old(self).thread_dom(),
