#[verifier::spinoff_prover]
    pub fn check_io_space_va_range_free(
        &self,
        target_proc_ptr: ProcPtr,
        va_range: &VaRange4K,
    ) -> (ret: bool)
        requires
            self.wf(),
            self.proc_dom().contains(target_proc_ptr),
            self.get_proc(target_proc_ptr).ioid.is_Some(),
            va_range.wf(),
        ensures
            ret == self.io_space_range_free(target_proc_ptr, va_range),
    {
        let target_ioid = self.proc_man.get_proc(target_proc_ptr).ioid.unwrap();
        for i in 0..va_range.len
            invariant
                self.mem_man.ioid_active(target_ioid),
                self.get_proc(target_proc_ptr).ioid.is_Some(),
                target_ioid == self.get_proc(target_proc_ptr).ioid.unwrap(),
                0 <= i <= va_range.len,
                self.wf(),
                self.proc_dom().contains(target_proc_ptr),
                va_range.wf(),
                forall|j: int|
                    #![auto]
                    0 <= j < i ==> self.get_io_space(target_proc_ptr).dom().contains(va_range@[j])
                        == false,
        {
            if self.mem_man.resolve_iommu_table_mapping(target_ioid, va_range.index(i)).is_some() {
                return false;
            }
        }
        return true;
    }

#[verifier::spinoff_prover]
    pub fn check_address_space_va_range_shareable(
        &self,
        target_proc_ptr: ProcPtr,
        va_range: &VaRange4K,
    ) -> (ret: bool)
        requires
            self.wf(),
            self.proc_dom().contains(target_proc_ptr),
            va_range.wf(),
        ensures
            ret == self.address_space_range_shareable(target_proc_ptr, va_range),
    {
        let target_pcid = self.proc_man.get_proc(target_proc_ptr).pcid;
        for i in 0..va_range.len
            invariant
                self.mem_man.pcid_active(target_pcid),
                target_pcid == self.get_proc(target_proc_ptr).pcid,
                0 <= i <= va_range.len,
                self.wf(),
                self.proc_dom().contains(target_proc_ptr),
                va_range.wf(),
                forall|j: int|
                    #![auto]
                    0 <= j < i ==> self.get_address_space(target_proc_ptr).dom().contains(
                        va_range@[j],
                    ),
                forall|j: int|
                    #![auto]
                    0 <= j < i ==> self.get_physical_page_reference_counter(
                        self.get_address_space(target_proc_ptr)[va_range@[j]].addr,
                    ) <= usize::MAX - va_range.len,
        {
            let entry_op = self.mem_man.resolve_pagetable_mapping(target_pcid, va_range.index(i));
            if entry_op.is_none() {
                return false;
            }
            assert(self.mem_man.get_pagetable_mapping_by_pcid(target_pcid).dom().contains(
                va_range@[i as int],
            ));
            let entry = entry_op.unwrap();
            if self.page_alloc.get_page_reference_counter(entry.addr) > usize::MAX - va_range.len {
                return false;
            }
        }
        return true;
    }

