pub fn get_address_space_va_range_none(
        &self,
        target_proc_ptr: ProcPtr,
        va_range: VaRange4K,
    ) -> (ret: bool)
        requires
            self.wf(),
            self.proc_dom().contains(target_proc_ptr),
            va_range.wf(),
        ensures
            ret == (forall|i: int|
                #![auto]
                0 <= i < va_range.len ==> self.get_address_space(target_proc_ptr).dom().contains(
                    va_range@[i],
                ) == false),
    {
        for i in 0..va_range.len
            invariant
                0 <= i <= va_range.len,
                self.wf(),
                self.proc_dom().contains(target_proc_ptr),
                va_range.wf(),
                forall|j: int|
                    #![auto]
                    0 <= j < i ==> self.get_address_space(target_proc_ptr).dom().contains(
                        va_range@[j],
                    ) == false,
        {
            let target_pcid = self.proc_man.get_proc(target_proc_ptr).pcid;
            if self.mem_man.resolve_pagetable_mapping(target_pcid, va_range.index(i)).is_some() {
                return false;
            }
        }
        return true;
    }

#[verifier::spinoff_prover]
    pub fn schedule_idle_cpu(&mut self, cpu_id: CpuId, pt_regs: &mut Registers) -> (ret:
        SyscallReturnStruct)
        requires
            old(self).wf(),
            0 <= cpu_id < NUM_CPUS,
        ensures
            self.wf(),
    {
        proof {
            self.proc_man.thread_inv();
            self.proc_man.endpoint_inv();
            self.proc_man.container_inv();
            self.proc_man.cpu_inv();
        }

        let container_ptr = self.proc_man.cpu_list.get(cpu_id).owning_container;

        if self.proc_man.cpu_list.get(cpu_id).active == false {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.cpu_list.get(cpu_id).current_thread.is_some() {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.get_container(container_ptr).scheduler.len() == 0 {
            return SyscallReturnStruct::NoNextThreadNew(RetValueType::Error);
        }
        let ret_thread_ptr = self.proc_man.pop_scheduler_for_idle_cpu(cpu_id, pt_regs);
        let proc_ptr = self.proc_man.get_thread(ret_thread_ptr).owning_proc;
        let pcid = self.proc_man.get_proc(proc_ptr).pcid;
        let cr3 = self.mem_man.get_cr3_by_pcid(pcid);
        return SyscallReturnStruct::SwitchNew(RetValueType::Else, cr3, pcid);
    }

pub fn syscall_io_mmap(&mut self, thread_ptr: ThreadPtr, va_range: VaRange4K) -> (ret:
        SyscallReturnStruct)
        requires
            old(self).total_wf(),
            old(self).thread_dom().contains(thread_ptr),
            va_range.wf(),
            va_range.len * 4 < usize::MAX,
    {
        let proc_ptr = self.proc_man.get_thread(thread_ptr).owning_proc;
        let ioid_op = self.proc_man.get_proc(proc_ptr).ioid;
        let container_ptr = self.proc_man.get_proc(proc_ptr).owning_container;

        proof {
            self.proc_man.thread_inv();
            self.proc_man.process_inv();
        }

        if ioid_op.is_none() {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        let ioid = ioid_op.unwrap();

        if self.proc_man.get_container(container_ptr).quota.mem_4k < va_range.len * 4 {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::ErrorNoQuota);
        }
        assert(self.page_alloc.free_pages_4k.len() >= va_range.len * 4) by {
            old(self).fold_mem_4k_lemma();
        }

        if self.check_io_space_va_range_free(proc_ptr, &va_range) == false {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::ErrorVaInUse);
        }
        let (num_page, seq_pages) = self.range_alloc_and_map_io(proc_ptr, &va_range);

        return SyscallReturnStruct::NoSwitchNew(RetValueType::SuccessSeqUsize { value: seq_pages });
    }

