#[verifier::spinoff_prover]
    pub fn syscall_new_thread(&mut self, thread_ptr: ThreadPtr, pt_regs: Registers) -> (ret:
        SyscallReturnStruct)
        requires
            old(self).wf(),
            old(self).thread_dom().contains(thread_ptr),
        ensures
            self.wf(),
            syscall_new_thread_requirement(*old(self), thread_ptr) == false
                <==> ret.is_error(),
    // syscall_new_thread_spec(*old(self),*self,cpu_id,pt_regs),

    {
        let proc_ptr = self.proc_man.get_owning_proc_by_thread_ptr(thread_ptr);
        if self.proc_man.get_proc(proc_ptr).owned_threads.len() >= MAX_NUM_THREADS_PER_PROC {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.get_container_by_proc_ptr(proc_ptr).quota.mem_4k == 0 {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.get_container_by_proc_ptr(proc_ptr).scheduler.len()
            >= MAX_CONTAINER_SCHEDULER_LEN {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.page_alloc.free_pages_4k.len() <= 0 {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        assert((self.get_num_of_free_pages() <= 0) == false);
        let (new_page_ptr, new_page_perm) = self.page_alloc.alloc_page_4k();
        let new_thread_ptr = self.proc_man.new_thread(
            proc_ptr,
            pt_regs,
            new_page_ptr,
            new_page_perm,
        );

        assert(self.memory_wf()) by {
            assert(self.mem_man.page_closure().disjoint(self.proc_man.page_closure()));
            assert(self.mem_man.page_closure() + self.proc_man.page_closure()
                == self.page_alloc.allocated_pages_4k());
            assert(self.page_alloc.mapped_pages_2m() =~= Set::empty());
            assert(self.page_alloc.mapped_pages_1g() =~= Set::empty());
            assert(self.page_alloc.allocated_pages_2m() =~= Set::empty());
            assert(self.page_alloc.allocated_pages_1g() =~= Set::empty());
        };
        assert(self.mapping_wf());
        assert(self.pcid_ioid_wf()) by {
            assert(forall|proc_ptr: ProcPtr|
                #![trigger self.proc_man.get_proc(proc_ptr).pcid]
                #![trigger self.proc_man.get_proc(proc_ptr).ioid]
                self.proc_man.proc_dom().contains(proc_ptr)
                    ==> self.mem_man.get_free_pcids_as_set().contains(
                    self.proc_man.get_proc(proc_ptr).pcid,
                ) == false && self.proc_man.get_proc(proc_ptr).ioid.is_Some()
                    ==> self.mem_man.get_free_ioids_as_set().contains(
                    self.proc_man.get_proc(proc_ptr).ioid.unwrap(),
                ) == false);
        };
        assert(forall|c: ContainerPtr|
            #![trigger self.get_container_owned_pages(c)]
            self.container_dom().contains(c) ==> old(self).page_alloc.get_container_owned_pages(c)
                =~= self.page_alloc.get_container_owned_pages(c));
        assert(forall|c: ContainerPtr|
            #![trigger self.get_container_owned_pages(c)]
            self.container_dom().contains(c) ==> old(self).get_container_owned_pages(c)
                =~= self.get_container_owned_pages(c));
        return SyscallReturnStruct::NoSwitchNew(
            RetValueType::SuccessUsize { value: new_thread_ptr },
        );
    }

#[verifier::spinoff_prover]
    pub fn syscall_receive_empty_block(
        &mut self,
        receiver_thread_ptr: ThreadPtr,
        blocking_endpoint_index: EndpointIdx,
        pt_regs: &Registers,
    ) -> (ret: SyscallReturnStruct)
        requires
            old(self).wf(),
            old(self).thread_dom().contains(receiver_thread_ptr),
            0 <= blocking_endpoint_index < MAX_NUM_ENDPOINT_DESCRIPTORS,
            old(self).get_thread(receiver_thread_ptr).state == ThreadState::RUNNING,
        ensures
    {
        proof {
            self.proc_man.thread_inv();
            self.proc_man.endpoint_inv();
        }

        let blocking_endpoint_ptr_op = self.proc_man.get_thread(
            receiver_thread_ptr,
        ).endpoint_descriptors.get(blocking_endpoint_index);

        if blocking_endpoint_ptr_op.is_none() {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        let blocking_endpoint_ptr = blocking_endpoint_ptr_op.unwrap();
        if self.proc_man.get_endpoint(blocking_endpoint_ptr).queue_state.is_receive()
            && self.proc_man.get_endpoint(blocking_endpoint_ptr).queue.len()
            < MAX_NUM_THREADS_PER_ENDPOINT {
            self.proc_man.block_running_thread_and_set_trap_frame(
                receiver_thread_ptr,
                blocking_endpoint_index,
                IPCPayLoad::Empty,
                pt_regs,
            );
            assert(self.wf());
            return SyscallReturnStruct::NoNextThreadNew(RetValueType::Error);
        }
        if self.proc_man.get_endpoint(blocking_endpoint_ptr).queue_state.is_receive()
            && self.proc_man.get_endpoint(blocking_endpoint_ptr).queue.len()
