            receiver_thread_ptr,
        ).endpoint_descriptors.get(endpoint_idx);

        if blocking_endpoint_ptr_op.is_none() {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        let blocking_endpoint_ptr = blocking_endpoint_ptr_op.unwrap();
        if self.proc_man.get_endpoint(blocking_endpoint_ptr).queue_state.is_receive()
            && self.proc_man.get_endpoint(blocking_endpoint_ptr).queue.len()
            < MAX_NUM_THREADS_PER_ENDPOINT {
            // Block
            self.proc_man.block_running_thread(
                receiver_thread_ptr,
                endpoint_idx,
                IPCPayLoad::Pages { va_range: receiver_va_range },
            );
            assert(self.wf());
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.get_endpoint(blocking_endpoint_ptr).queue_state.is_receive()
            && self.proc_man.get_endpoint(blocking_endpoint_ptr).queue.len()
            >= MAX_NUM_THREADS_PER_ENDPOINT {
            // queue is full return error
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.get_endpoint(blocking_endpoint_ptr).queue_state.is_send()
            && self.proc_man.get_endpoint(blocking_endpoint_ptr).queue.len() == 0 {
            // change queue state and Block
            self.proc_man.block_running_thread_and_change_queue_state(
                receiver_thread_ptr,
                endpoint_idx,
                IPCPayLoad::Pages { va_range: receiver_va_range },
                EndpointState::RECEIVE,
            );
            assert(self.wf());
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        assert(self.sender_exist(receiver_thread_ptr, endpoint_idx));

        let sender_thread_ptr = self.proc_man.get_endpoint(blocking_endpoint_ptr).queue.get_head();
        let sender_proc_ptr = self.proc_man.get_thread(sender_thread_ptr).owning_proc;
        let sender_container_ptr = self.proc_man.get_thread(sender_thread_ptr).owning_container;
        let sender_endpoint_payload_op = self.proc_man.get_thread(
            sender_thread_ptr,
        ).ipc_payload.get_payload_as_va_range();

        if self.proc_man.get_container(sender_container_ptr).scheduler.len()
            >= MAX_CONTAINER_SCHEDULER_LEN {
            // cannot schedule the sender
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if sender_endpoint_payload_op.is_none() {
            // sender didn't send any pages
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        let sender_va_range = sender_endpoint_payload_op.unwrap();

        if receiver_va_range.len != sender_va_range.len {
            // @Xiangdong TODO schedule the threads and return error
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if !self.check_address_space_va_range_shareable(sender_proc_ptr, &sender_va_range)
            || !self.check_address_space_va_range_free(receiver_proc_ptr, &receiver_va_range) {
            // sender pages not shareable or  receiver pages not free
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.proc_man.get_container(receiver_container_ptr).quota.mem_4k < receiver_va_range.len
            * 3 {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if self.page_alloc.free_pages_4k.len() < receiver_va_range.len * 3 {
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        if receiver_proc_ptr == sender_proc_ptr {
            // @Xiangdong TODO allow sharing between same procs
            return SyscallReturnStruct::NoSwitchNew(RetValueType::Error);
        }
        assert(old(self).get_container(
            old(self).get_thread(
                old(self).get_endpoint(blocking_endpoint_ptr).queue@[0],
            ).owning_container,
        ).scheduler.len() < MAX_CONTAINER_SCHEDULER_LEN);
        self.range_create_and_share_mapping(
            sender_proc_ptr,
            &sender_va_range,
            receiver_proc_ptr,
            &receiver_va_range,
        );
        self.proc_man.schedule_blocked_thread(blocking_endpoint_ptr);
        return SyscallReturnStruct::NoSwitchNew(RetValueType::Else);
    }

#[verifier::spinoff_prover]
    pub fn alloc_iommu_table(&mut self, new_proc_ptr: ProcPtr) -> (ret: IOid)
        requires
            old(self).wf(),
            old(self).free_ioids.len() > 0,
        ensures
            self.wf(),
            self.kernel_entries =~= old(self).kernel_entries,
            self.kernel_entries_ghost =~= old(self).kernel_entries_ghost,
            self.free_pcids =~= old(self).free_pcids,
            self.page_tables =~= old(self).page_tables,
            self.page_table_pages =~= old(self).page_table_pages,
            // self.free_ioids =~= old(self).free_ioids,
            self.iommu_tables =~= old(self).iommu_tables,
            self.iommu_table_pages =~= old(self).iommu_table_pages,
            self.root_table =~= old(self).root_table,
            self.root_table_cache =~= old(self).root_table_cache,
            self.pci_bitmap =~= old(self).pci_bitmap,
            self.page_table_pages@.dom() =~= old(self).page_table_pages@.dom(),
            forall|p: Pcid|
                #![trigger self.pcid_active(p)]
                self.pcid_active(p) == old(self).pcid_active(p),
            forall|p: IOid|
                #![trigger self.ioid_active(p)]
                p != ret ==> self.ioid_active(p) == old(self).ioid_active(p),
            forall|p: IOid|
                #![trigger self.ioid_active(p)]
                #![trigger self.get_iommu_table_mapping_by_ioid(p)]
                self.ioid_active(p) && p != ret ==> old(self).get_iommu_table_mapping_by_ioid(p)
                    == self.get_iommu_table_mapping_by_ioid(p),
            forall|i: Pcid|
                #![trigger self.pcid_active(i)]
                #![trigger self.get_pagetable_mapping_by_pcid(i)]
                self.pcid_active(i) ==> old(self).get_pagetable_mapping_by_pcid(i)
                    == self.get_pagetable_mapping_by_pcid(i),
            forall|p: Pcid|
                #![trigger self.pcid_active(p)]
                #![trigger self.pcid_to_proc_ptr(p)]
                self.pcid_active(p) ==> old(self).pcid_to_proc_ptr(p) == self.pcid_to_proc_ptr(p),
            forall|p: IOid|
                #![trigger self.ioid_active(p)]
                #![trigger self.ioid_to_proc_ptr(p)]
                self.ioid_active(p) && p != ret ==> old(self).ioid_to_proc_ptr(p)
                    == self.ioid_to_proc_ptr(p),
            self.ioid_to_proc_ptr(ret) == new_proc_ptr,
            self.ioid_active(ret),
            !old(self).ioid_active(ret),
            self.get_iommu_table_mapping_by_ioid(ret).dom() == Set::<PagePtr>::empty(),
    {
        let new_ioid = *self.free_ioids.pop_unique();
        self.ioid_to_proc_ptr.set(new_ioid, Some(new_proc_ptr));
        assert(self.pagetables_wf());
        assert(self.iommutables_wf()) by {
            seq_pop_unique_lemma::<IOid>();
            seq_update_lemma::<Option<PageTable>>();
            assert(forall|ioid: IOid|
                ioid != new_ioid ==> old(self).get_free_ioids_as_set().contains(ioid)
                    == self.get_free_ioids_as_set().contains(ioid));
        };
        assert(self.pagetable_iommu_table_disjoint());
        assert(self.root_table_wf());
        assert(self.root_table_cache_wf());
        assert(self.kernel_entries_wf());
        assert(self.ioid_to_proc_wf()) by {
            set_lemma::<IOid>();
            seq_pop_unique_lemma::<IOid>();
            seq_update_lemma::<ProcPtr>();
            //    assert(
            //         forall|pcid:Pcid|
            //         #![trigger self.pcid_active(pcid)]
            //         #![trigger self.pcid_to_proc_ptr@[pcid as int]]
            //         pcid != new_pcid ==>
            //         self.pcid_active(pcid) == self.pcid_to_proc_ptr@[pcid as int].is_Some()
            //    );
        };
        assert(self.pcid_to_proc_wf());
        new_ioid
    }

