pub fn new_thread(
        &mut self,
        proc_ptr: ProcPtr,
        pt_regs: Registers,
        page_ptr: PagePtr,
        page_perm: Tracked<PagePerm4k>,
    ) -> (ret: ThreadPtr)
        requires
            old(self).wf(),
            old(self).proc_dom().contains(proc_ptr),
            old(self).page_closure().contains(page_ptr) == false,
            old(self).get_proc(proc_ptr).owned_threads.len() < MAX_NUM_THREADS_PER_PROC,
            old(self).get_container_by_proc_ptr(proc_ptr).quota.mem_4k > 0,
            old(self).get_container_by_proc_ptr(proc_ptr).scheduler.len()
                < MAX_CONTAINER_SCHEDULER_LEN,
            page_perm@.is_init(),
            page_perm@.addr() == page_ptr,
        ensures
            self.wf(),
            self.page_closure() =~= old(self).page_closure().insert(page_ptr),
            self.proc_dom() =~= old(self).proc_dom(),
            self.endpoint_dom() == old(self).endpoint_dom(),
            self.container_dom() == old(self).container_dom(),
            self.thread_dom() == old(self).thread_dom().insert(ret),
            old(self).get_container(
                old(self).get_proc(proc_ptr).owning_container,
            ).quota.spec_subtract_mem_4k(
                self.get_container(self.get_proc(proc_ptr).owning_container).quota,
                1,
            ),
            old(self).get_proc(proc_ptr).pcid =~= self.get_proc(proc_ptr).pcid,
            old(self).get_proc(proc_ptr).ioid =~= self.get_proc(proc_ptr).ioid,
            forall|p_ptr: ProcPtr|
                #![trigger self.get_proc(p_ptr)]
                self.proc_dom().contains(p_ptr) && p_ptr != proc_ptr ==> self.get_proc(p_ptr)
                    =~= old(self).get_proc(p_ptr),
            forall|container_ptr: ContainerPtr|
                #![trigger self.get_container(container_ptr).owned_procs]
                self.container_dom().contains(container_ptr) && container_ptr != self.get_proc(
                    proc_ptr,
                ).owning_container ==> self.get_container(container_ptr).owned_procs =~= old(
                    self,
                ).get_container(container_ptr).owned_procs,
    {
        // proof{seq_push_lemma::<ThreadPtr>();}
        broadcast use ProcessManager::reveal_process_manager_wf;

        let container_ptr = self.get_proc(proc_ptr).owning_container;
        let old_mem_quota = self.get_container(container_ptr).quota.mem_4k;
        let old_owned_threads = self.get_container(container_ptr).owned_threads;
        let mut proc_perm = Tracked(self.process_perms.borrow_mut().tracked_remove(proc_ptr));
        let proc_node_ref = proc_push_thread(proc_ptr, &mut proc_perm, &page_ptr);
        proof {
            self.process_perms.borrow_mut().tracked_insert(proc_ptr, proc_perm.get());
        }

        let mut container_perm = Tracked(
            self.container_perms.borrow_mut().tracked_remove(container_ptr),
        );
        let scheduler_node_ref = scheduler_push_thread(
            container_ptr,
            &mut container_perm,
            &page_ptr,
        );
        container_set_quota_mem_4k(container_ptr, &mut container_perm, old_mem_quota - 1);
        container_set_owned_threads(
            container_ptr,
            &mut container_perm,
            Ghost(old_owned_threads@.insert(page_ptr)),
        );
        proof {
            self.container_perms.borrow_mut().tracked_insert(container_ptr, container_perm.get());
        }

        let (thread_ptr, thread_perm) = page_to_thread(
            page_ptr,
            page_perm,
            &pt_regs,
            container_ptr,
            proc_ptr,
            proc_node_ref,
            scheduler_node_ref,
        );

        proof {
            self.thread_perms.borrow_mut().tracked_insert(thread_ptr, thread_perm.get());
        }

        assert(self.container_perms_wf());
        assert(self.container_tree_wf()) by {
            container_no_change_to_tree_fields_imply_wf(
                self.root_container,
                old(self).container_perms@,
                self.container_perms@,
            );
        };
        assert(self.container_fields_wf());
        assert(self.proc_perms_wf()) by {
            assert(forall|p_ptr: ProcPtr|
                #![auto]
                self.process_perms@.dom().contains(p_ptr) && proc_ptr != p_ptr ==> old(
                    self,
                ).process_perms@[p_ptr].value().subtree_set
                    =~= self.process_perms@[p_ptr].value().subtree_set);
        };
        assert(self.process_trees_wf()) by {
            // seq_to_set_lemma::<ProcPtr>();
            assert forall|c_ptr: ContainerPtr|
                #![trigger self.container_dom().contains(c_ptr)]
                #![trigger self.process_tree_wf(c_ptr)]
                self.container_dom().contains(c_ptr) && self.get_container(
                    c_ptr,
                ).root_process.is_Some() implies self.process_tree_wf(c_ptr) by {
                process_no_change_to_trees_fields_imply_wf(
                    self.get_container(c_ptr).root_process.unwrap(),
                    self.get_container(c_ptr).owned_procs@.to_set(),
                    old(self).process_perms@,
                    self.process_perms@,
                );
            };
        };
        assert(self.process_fields_wf()) by {
            assert(forall|p_ptr: ProcPtr|
                #![trigger self.get_proc(p_ptr)]
                self.proc_dom().contains(p_ptr) && proc_ptr != p_ptr ==> self.get_proc(p_ptr)
                    =~= old(self).get_proc(p_ptr));
        };
        assert(self.cpus_wf());
        assert(self.container_cpu_wf());
        assert(self.memory_disjoint());
        assert(self.container_perms_wf());
        assert(self.processes_container_wf());
        assert(self.threads_process_wf()) by {
            seq_push_lemma::<ThreadPtr>();
            assert(forall|p_ptr: ProcPtr|
                #![auto]
                self.process_perms@.dom().contains(p_ptr) && p_ptr != proc_ptr ==> old(
                    self,
                ).process_perms@[p_ptr].value().owned_threads
                    =~= self.process_perms@[p_ptr].value().owned_threads);
        };
        assert(self.threads_perms_wf());
        assert(self.endpoint_perms_wf());
        assert(self.threads_endpoint_descriptors_wf());
        assert(self.endpoints_queue_wf());
        assert(self.endpoints_container_wf());
        assert(self.schedulers_wf()) by {
            seq_push_lemma::<ThreadPtr>();
        };
        assert(self.pcid_ioid_wf());
        assert(self.threads_cpu_wf());
        assert(self.threads_container_wf());
        thread_ptr
    }

#[verifier::spinoff_prover]
pub fn proc_tree_check_is_ancestor(
    root_proc: ProcPtr,
    proc_tree_dom: Ghost<Set<ProcPtr>>,
    proc_perms: &Tracked<Map<ProcPtr, PointsTo<Process>>>,
    a_ptr: ProcPtr,
    child_ptr: ProcPtr,
) -> (ret: bool)
    requires
        proc_perms_wf(proc_perms@),
        proc_tree_wf(root_proc, proc_tree_dom@, proc_perms@),
        proc_tree_dom_subset_of_proc_dom(proc_tree_dom@, proc_perms@),
        proc_tree_dom@.contains(a_ptr),
        proc_tree_dom@.contains(child_ptr),
        proc_perms@[a_ptr].value().depth < proc_perms@[child_ptr].value().depth,
        child_ptr != root_proc,
    ensures
        ret == proc_perms@[child_ptr].value().uppertree_seq@.contains(a_ptr),
{
    // assert(false);
    proof {
        seq_push_lemma::<ProcPtr>();
    }
    assert(proc_perms@[child_ptr].value().parent.is_Some());
    let tracked child_perm = proc_perms.borrow().tracked_borrow(child_ptr);
    let child: &Process = PPtr::<Process>::from_usize(child_ptr).borrow(Tracked(child_perm));
    let mut current_parent_ptr = child.parent.unwrap();
    let mut depth = child.depth;
    assert(current_parent_ptr == proc_perms@[child_ptr].value().uppertree_seq@[depth - 1]);

    if current_parent_ptr == a_ptr {
        return true;
    }
    while depth != 1
        invariant
            1 <= depth <= proc_perms@[child_ptr].value().depth,
            proc_perms_wf(proc_perms@),
            proc_tree_wf(root_proc, proc_tree_dom@, proc_perms@),
            proc_tree_dom_subset_of_proc_dom(proc_tree_dom@, proc_perms@),
            proc_tree_dom@.contains(a_ptr),
            proc_tree_dom@.contains(child_ptr),
            proc_perms@[a_ptr].value().depth < proc_perms@[child_ptr].value().depth,
            child_ptr != root_proc,
            current_parent_ptr == proc_perms@[child_ptr].value().uppertree_seq@[depth - 1],
            forall|i: int|
                #![auto]
                depth - 1 <= i < proc_perms@[child_ptr].value().depth
                    ==> proc_perms@[child_ptr].value().uppertree_seq@[i] != a_ptr,
        ensures
            depth == 1,
            forall|i: int|
                #![auto]
                0 <= i < proc_perms@[child_ptr].value().depth
                    ==> proc_perms@[child_ptr].value().uppertree_seq@[i] != a_ptr,
        decreases depth,
    {
        assert(proc_perms@[child_ptr].value().uppertree_seq@.contains(current_parent_ptr));
        assert(proc_perms@.dom().contains(current_parent_ptr));
        assert(proc_perms@[child_ptr].value().uppertree_seq@.no_duplicates());
        assert(proc_perms@[child_ptr].value().uppertree_seq@.index_of(current_parent_ptr) == depth
            - 1);
        assert(proc_perms@[current_parent_ptr].value().depth == depth - 1);
        assert(proc_perms@[current_parent_ptr].value().parent.is_Some());
        let tracked current_parent_perm = proc_perms.borrow().tracked_borrow(current_parent_ptr);
        assert(current_parent_perm.addr() == current_parent_ptr);
        let current_parent: &Process = PPtr::<Process>::from_usize(current_parent_ptr).borrow(
            Tracked(current_parent_perm),
        );
        let current_parent_ptr_tmp = current_parent.parent.unwrap();
        if current_parent_ptr_tmp == a_ptr {
            assert(proc_perms@[current_parent_ptr].value().uppertree_seq@[depth - 1 - 1]
                == current_parent_ptr_tmp);
            return true;
        }
        assert(proc_perms@[current_parent_ptr].value().uppertree_seq@[depth - 1 - 1]
            == current_parent_ptr_tmp);
        current_parent_ptr = current_parent_ptr_tmp;
        depth = depth - 1;
    }
    false
}

#[verifier::spinoff_prover]
    pub fn init(&mut self)
        requires
            N > 2,
            N < SLLIndex::MAX,
            old(self).array_wf(),
        ensures
            self.wf(),
            self@ =~= Seq::empty(),
            self.len() == 0,
    {
        self.spec_seq = Ghost(Seq::empty());

        self.value_list = Ghost(Seq::empty());
        self.value_list_head = -1;
        self.value_list_tail = -1;
        self.value_list_len = 0;

        self.free_list = Ghost(Seq::empty());
        self.free_list_head = -1;
        self.free_list_tail = -1;
        self.free_list_len = 0;

        assert(self.value_list_wf());
        assert(self.free_list_wf());
        assert(self.spec_seq_wf());
        assert(forall|i: int, j: int|
            #![trigger self.value_list@[i], self.free_list@[j]]
            0 <= i < self.value_list@.len() && 0 <= j < self.free_list@.len()
                ==> self.value_list@[i] != self.free_list@[j]);

        for i in 0..N
            invariant
                0 <= i <= N,
                N > 2,
                N < SLLIndex::MAX,
                self.array_wf(),
                self.free_list_len == i,
                self.free_list_len + self.value_list_len == i,
                self.value_list_wf(),
                self.free_list_wf(),
                self.spec_seq_wf(),
                forall|i: int, j: int|
                    #![trigger self.value_list@[i], self.free_list@[j]]
                    0 <= i < self.value_list@.len() && 0 <= j < self.free_list@.len()
                        ==> self.value_list@[i] != self.free_list@[j],
                forall|j: int|
                    #![trigger self.free_list@[j]]
                    0 <= j < self.free_list_len ==> self.free_list@[j] == j as SLLIndex,
        {
            self.free_list_len = self.free_list_len + 1;
            if i == 0 {
                self.free_list_head = 0;
                self.free_list_tail = 0;
                self.free_list = Ghost(Seq::empty().push(0));
                self.set_prev(0 as SLLIndex, -1);
                self.set_next(0 as SLLIndex, -1);
                self.set_value(0 as SLLIndex, None);
                assert(self.free_list_wf());
            } else {
                self.free_list = Ghost(self.free_list@.push(i as SLLIndex));
                self.set_next(self.free_list_tail, i as SLLIndex);
                self.set_prev(i as SLLIndex, self.free_list_tail);
                self.set_next(i as SLLIndex, -1);
                self.set_value(i as SLLIndex, None);
                self.free_list_tail = i as SLLIndex;
                assert(self.free_list_wf());
            }
        }
        assert(self.wf());
    }

pub fn remove_helper1(&mut self, remove_index: SLLIndex, v: Ghost<T>) -> (ret: T)
        requires
            old(self).wf(),
            old(self)@.contains(v@),
            old(self).get_node_ref(v@) == remove_index,
            old(self).value_list_len == 1,
        ensures
            self.wf(),
            self.len() == old(self).len() - 1,
            ret == v@,
            self.unique(),
            self@ =~= old(self)@.remove_value(ret),
            forall|v:T|
                #![auto]
                self@.contains(v) ==> 
                    old(self).get_node_ref(v) == 
                        self.get_node_ref(v),
    {
        proof {
            seq_push_lemma::<SLLIndex>();
            seq_skip_lemma::<SLLIndex>();
            seq_skip_lemma::<T>();
            seq_skip_index_of_lemma::<T>();
        }
        let ret = self.get_value(remove_index).unwrap();
        let old_free_list_tail = self.free_list_tail;
        self.set_next(old_free_list_tail, remove_index);
        self.set_prev(remove_index, old_free_list_tail);
        self.free_list_tail = remove_index;
        self.free_list_len = self.free_list_len + 1;
        proof {
            self.free_list@ = self.free_list@.push(remove_index);
        }

        self.value_list_head = -1;
        self.value_list_tail = -1;
        proof {
            self.value_list@ = self.value_list@.skip(1);
            self.spec_seq@ = self.spec_seq@.skip(1);
        }
        self.value_list_len = self.value_list_len - 1;

        assert(self.wf());
        return ret;
    }

pub fn pop(&mut self) -> (ret: (T, SLLIndex))
        requires
            old(self).wf(),
            old(self).len() > 0,
            old(self).unique(),
            N > 2,
        ensures
            self.wf(),
            self.len() == old(self).len() - 1,
            self@ == old(self)@.skip(1),
            ret.0 == old(self)@[0],
            ret.1 == old(self).get_node_ref(ret.0),
            forall|v:T|
                #![auto]
                self@.contains(v) ==> 
                    old(self).get_node_ref(v) == 
                        self.get_node_ref(v),
    {
        proof {
            seq_push_lemma::<SLLIndex>();
            seq_skip_lemma::<SLLIndex>();
            seq_skip_lemma::<T>();
            seq_skip_index_of_lemma::<T>();
        }
        if self.free_list_len == 0 {
            let ret_index = self.value_list_head;
            let ret = self.get_value(ret_index).unwrap();

            let new_value_list_head = self.get_next(ret_index);
            self.value_list_head = new_value_list_head;
            self.set_prev(new_value_list_head, -1);
            proof {
                self.value_list@ = self.value_list@.skip(1);
                self.spec_seq@ = self.spec_seq@.skip(1);
            }
            self.value_list_len = self.value_list_len - 1;

            self.free_list_head = ret_index;
            self.free_list_tail = ret_index;
            self.set_prev(ret_index, -1);
            self.set_next(ret_index, -1);
            proof {
                self.free_list@ = self.free_list@.push(ret_index);
            }
            self.free_list_len = self.free_list_len + 1;

            assert(self.wf());
            return (ret, ret_index);
        } else if self.value_list_len == 1 {
            let ret_index = self.value_list_head;
            let ret = self.get_value(ret_index).unwrap();

            let old_free_list_tail = self.free_list_tail;
            self.set_next(old_free_list_tail, ret_index);
            self.set_prev(ret_index, old_free_list_tail);
            self.free_list_tail = ret_index;
            self.free_list_len = self.free_list_len + 1;
            proof {
                self.free_list@ = self.free_list@.push(ret_index);
            }

            self.value_list_head = -1;
            self.value_list_tail = -1;
            proof {
                self.value_list@ = self.value_list@.skip(1);
                self.spec_seq@ = self.spec_seq@.skip(1);
            }
            self.value_list_len = self.value_list_len - 1;

            assert(self.wf());

            return (ret, ret_index);
        } else {
            let ret_index = self.value_list_head;
            let ret = self.get_value(ret_index).unwrap();

            let new_value_list_head = self.get_next(ret_index);
            self.value_list_head = new_value_list_head;
            self.set_prev(new_value_list_head, -1);
            proof {
                self.value_list@ = self.value_list@.skip(1);
                self.spec_seq@ = self.spec_seq@.skip(1);
            }
            self.value_list_len = self.value_list_len - 1;

            let old_free_list_tail = self.free_list_tail;
            self.set_next(ret_index, -1);
            self.set_next(old_free_list_tail, ret_index);
            self.set_prev(ret_index, old_free_list_tail);
            self.free_list_tail = ret_index;
            self.free_list_len = self.free_list_len + 1;
            proof {
                self.free_list@ = self.free_list@.push(ret_index);
            }
            assert(self.wf());
            return (ret, ret_index);
        }
    }

#[verifier::spinoff_prover]
    pub fn push(&mut self, new_value: &T) -> (free_node_index: SLLIndex)
        requires
            old(self).wf(),
            old(self).len() < N,
            old(self).unique(),
            old(self)@.contains(*new_value) == false,
            N > 2,
        ensures
            self.wf(),
            self@ == old(self)@.push(*new_value),
            self.len() == old(self).len() + 1,
            forall|v:T|
                #![auto]
                old(self)@.contains(v) ==> 
                    old(self).get_node_ref(v) == 
                        self.get_node_ref(v),
            self.get_node_ref(*new_value) == free_node_index,
            self.unique(),
    {
        proof {
            seq_push_lemma::<SLLIndex>();
            seq_push_lemma::<T>();
            seq_push_index_of_lemma::<T>();
        }
        if self.value_list_len == 0 {
            // value list empty
            // assert(self.value_list_head == -1);
            // assert(self.value_list_tail == -1);
            let ret = self.free_list_head;
            // assert(ret != -1);
            // assert(ret != self.free_list_tail);
            let next_free_list_head = self.get_next(self.free_list_head);
            // assert(next_free_list_head == self.free_list@[1]);
            self.free_list_head = next_free_list_head;
            self.set_prev(self.free_list_head, -1);

            self.free_list_len = self.free_list_len - 1;
            proof {
                self.free_list@ = self.free_list@.skip(1);
            }
            self.value_list_head = ret;
            self.value_list_tail = ret;
            self.set_prev(ret, -1);

            assert(forall|i: nat|
                #![trigger old(self).arr_seq@[i as int]]
                #![trigger self.arr_seq@[i as int], old(self).arr_seq@[i as int]]
                0 <= i < N && i != ret ==> old(self).arr_seq@[i as int].next
                    == self.arr_seq@[i as int].next);

            self.set_next(ret, -1);
            proof {
                self.value_list@ = self.value_list@.push(ret);
                self.spec_seq@ = self.spec_seq@.push(*new_value);
            }
            self.value_list_len = self.value_list_len + 1;
            self.set_value(ret, Some(*new_value));

            assert(self.wf());
            assert(self@ == old(self)@.push(*new_value));
            return ret;
        } else if self.free_list_len == 1 {
            let ret = self.free_list_tail;
            self.free_list_len = 0;
            self.free_list_head = -1;
            self.free_list_tail = -1;
            proof {
                self.free_list@ = self.free_list@.skip(1);
            }

            let old_value_list_tail = self.value_list_tail;
            self.set_prev(ret, old_value_list_tail);
            self.set_next(old_value_list_tail, ret);
            self.value_list_tail = ret;
            proof {
                self.value_list@ = self.value_list@.push(ret);
                self.spec_seq@ = self.spec_seq@.push(*new_value);
            }
            self.value_list_len = self.value_list_len + 1;

            self.set_value(ret, Some(*new_value));

            assert(self.wf());
            assert(self@ == old(self)@.push(*new_value));
            return ret;

        } else {
            assert(self.free_list_len > 1 && self.value_list_len > 0);
            let ret = self.free_list_head;
            let old_value_list_tail = self.value_list_tail;

            let new_free_list_head = self.get_next(ret);
            self.set_prev(new_free_list_head, -1);
            self.free_list_head = new_free_list_head;
            self.free_list_len = self.free_list_len - 1;
            proof {
                self.free_list@ = self.free_list@.skip(1);
            }
            self.set_next(old_value_list_tail, ret);
            self.set_prev(ret, old_value_list_tail);
            self.set_next(ret, -1);
            self.value_list_tail = ret;
            self.value_list_len = self.value_list_len + 1;
            proof {
                self.value_list@ = self.value_list@.push(ret);
                self.spec_seq@ = self.spec_seq@.push(*new_value);
            }
            self.set_value(ret, Some(*new_value));
            assert(self.wf());
            return ret;
        }
    }

